import { useState } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useTranslation } from 'react-i18next'
import { Plus, Wrench, AlertTriangle } from 'lucide-react'
import { Button } from '@components/shared/Button'
import { Input } from '@components/shared/Input'
import { Table, Column, Pagination } from '@components/shared/Table'
import { Badge, statusVariant } from '@components/shared/Badge'
import { Modal } from '@components/shared/Modal'
import { DateDisplay } from '@components/shared/DateDisplay'
import { usePagination } from '@hooks/usePagination'
import apiClient from '@services/api'
import { formatNPR } from '@utils/nepaliDate'
import { useUiStore } from '@store/uiStore'
import toast from 'react-hot-toast'
import { useForm } from 'react-hook-form'

interface MaintenanceRecord {
  id: string
  vehicle_plate: string
  maintenance_type: string
  status: string
  scheduled_date: string
  completed_date: string | null
  technician: string
  cost: number
  notes: string | null
}

export default function MaintenancePage() {
  const { t } = useTranslation('tenant')
  const { language } = useUiStore()
  const qc = useQueryClient()
  const [showCreate, setShowCreate] = useState(false)
  const [totalCount, setTotalCount] = useState(0)
  const pagination = usePagination(totalCount)

  const { data, isLoading } = useQuery({
    queryKey: ['maintenance', pagination.page],
    queryFn: async () => {
      const { data } = await apiClient.get('/maintenance/schedules/', { params: pagination.queryParams })
      setTotalCount(data.meta?.total_count ?? 0)
      return data.data?.results ?? []
    },
  })

  const { register, handleSubmit, reset } = useForm<Partial<MaintenanceRecord>>()

  const createMutation = useMutation({
    mutationFn: (payload: Partial<MaintenanceRecord>) =>
      apiClient.post('/maintenance/schedules/', payload).then((r) => r.data),
    onSuccess: () => {
      toast.success('Maintenance scheduled!')
      setShowCreate(false)
      reset()
      qc.invalidateQueries({ queryKey: ['maintenance'] })
    },
    onError: (err: Error) => toast.error(err.message),
  })

  const columns: Column<MaintenanceRecord>[] = [
    { key: 'vehicle_plate', header: 'Vehicle', render: (m) => <span className="font-mono font-bold">{m.vehicle_plate}</span> },
    { key: 'maintenance_type', header: t('maintenance.maintenanceType'),
      render: (m) => <Badge variant="neutral">{m.maintenance_type}</Badge> },
    { key: 'status', header: 'Status',
      render: (m) => <Badge variant={statusVariant(m.status)} dot>{m.status}</Badge> },
    { key: 'scheduled_date', header: t('maintenance.scheduledDate'),
      render: (m) => {
        const isPast = new Date(m.scheduled_date) < new Date()
        return (
          <div className="flex items-center gap-2">
            <DateDisplay date={m.scheduled_date} />
            {isPast && m.status === 'SCHEDULED' && <AlertTriangle className="h-4 w-4 text-red-500" />}
          </div>
        )
      }
    },
    { key: 'completed_date', header: t('maintenance.completedDate'),
      render: (m) => m.completed_date ? <DateDisplay date={m.completed_date} /> : '—' },
    { key: 'technician', header: t('maintenance.technician') },
    { key: 'cost', header: t('maintenance.cost'),
      render: (m) => m.cost ? formatNPR(m.cost, language as 'en' | 'ne') : '—' },
  ]

  return (
    <div className="space-y-6">
      <div className="page-header">
        <div>
          <h1 className="page-title">{t('maintenance.title')}</h1>
        </div>
        <Button leftIcon={<Plus className="h-4 w-4" />} onClick={() => setShowCreate(true)}>
          {t('maintenance.scheduleService')}
        </Button>
      </div>

      <div className="card p-0">
        <Table columns={columns} data={data ?? []} keyExtractor={(m) => m.id} loading={isLoading} />
        <Pagination
          page={pagination.page}
          totalPages={pagination.totalPages}
          totalCount={totalCount}
          pageSize={pagination.pageSize}
          onPageChange={pagination.setPage}
        />
      </div>

      <Modal open={showCreate} onClose={() => setShowCreate(false)} title={t('maintenance.scheduleService')} size="md">
        <form onSubmit={handleSubmit((d) => createMutation.mutate(d))} className="space-y-4 p-6">
          <Input label="Vehicle ID" required {...register('vehicle_plate', { required: true })} />
          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">{t('maintenance.maintenanceType')}</label>
            <select className="w-full rounded-lg border px-3 py-2 text-sm" {...register('maintenance_type')}>
              <option value="ROUTINE">Routine Service</option>
              <option value="REPAIR">Repair</option>
              <option value="INSPECTION">Inspection</option>
              <option value="EMERGENCY">Emergency</option>
              <option value="TIRE">Tire Change</option>
              <option value="OIL">Oil Change</option>
            </select>
          </div>
          <Input label={t('maintenance.scheduledDate')} type="date" required {...register('scheduled_date', { required: true })} />
          <Input label={t('maintenance.technician')} {...register('technician')} />
          <Input label={t('maintenance.cost')} type="number" step="0.01" {...register('cost')} />
          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">{t('maintenance.notes')}</label>
            <textarea className="w-full rounded-lg border px-3 py-2 text-sm" rows={3} {...register('notes')} />
          </div>
          <div className="flex justify-end gap-3 border-t pt-4">
            <Button variant="secondary" type="button" onClick={() => setShowCreate(false)}>Cancel</Button>
            <Button type="submit" loading={createMutation.isPending} leftIcon={<Wrench className="h-4 w-4" />}>
              Schedule
            </Button>
          </div>
        </form>
      </Modal>
    </div>
  )
}
