import { useQuery } from '@tanstack/react-query'
import { useTranslation } from 'react-i18next'
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LineChart, Line } from 'recharts'
import { StatCard } from '@components/shared/StatCard'
import { Table, Column } from '@components/shared/Table'
import { TrendingUp, DollarSign } from 'lucide-react'
import apiClient from '@services/api'
import { formatNPR } from '@utils/nepaliDate'
import { useUiStore } from '@store/uiStore'
import { DateDisplay } from '@components/shared/DateDisplay'

interface RevenueRecord {
  id: string
  trip_id: string
  route_number: string
  total_amount: number
  platform_commission: number
  operator_share: number
  date: string
  payment_method: string
}

export default function RevenuePage() {
  const { t } = useTranslation('tenant')
  const { language } = useUiStore()

  const { data: summary } = useQuery({
    queryKey: ['revenue-summary'],
    queryFn: async () => {
      const { data } = await apiClient.get('/revenue/summary/')
      return data.data
    },
  })

  const { data: records } = useQuery({
    queryKey: ['revenue-records'],
    queryFn: async () => {
      const { data } = await apiClient.get('/revenue/records/?page_size=20')
      return data.data?.results ?? []
    },
  })

  const { data: byRoute } = useQuery({
    queryKey: ['revenue-by-route'],
    queryFn: async () => {
      const { data } = await apiClient.get('/revenue/by-route/')
      return data.data ?? []
    },
  })

  const columns: Column<RevenueRecord>[] = [
    { key: 'route_number', header: 'Route', render: (r) => <span className="font-mono font-bold">{r.route_number}</span> },
    { key: 'total_amount', header: t('revenue.totalAmount'), render: (r) => formatNPR(r.total_amount, language as 'en' | 'ne') },
    { key: 'platform_commission', header: t('revenue.platformCommission'), render: (r) => formatNPR(r.platform_commission, language as 'en' | 'ne') },
    { key: 'operator_share', header: t('revenue.operatorShare'), render: (r) => <span className="text-green-600 font-semibold">{formatNPR(r.operator_share, language as 'en' | 'ne')}</span> },
    { key: 'payment_method', header: 'Payment Method' },
    { key: 'date', header: 'Date', render: (r) => <DateDisplay date={r.date} /> },
  ]

  return (
    <div className="space-y-6">
      <div className="page-header">
        <h1 className="page-title">{t('revenue.title')}</h1>
      </div>

      <div className="grid grid-cols-2 gap-4 lg:grid-cols-4">
        <StatCard title={t('revenue.daily')} value={formatNPR(summary?.daily ?? 0, language as 'en' | 'ne')} icon={<DollarSign className="h-6 w-6" />} />
        <StatCard title={t('revenue.weekly')} value={formatNPR(summary?.weekly ?? 0, language as 'en' | 'ne')} icon={<TrendingUp className="h-6 w-6" />} />
        <StatCard title={t('revenue.monthly')} value={formatNPR(summary?.monthly ?? 0, language as 'en' | 'ne')} icon={<TrendingUp className="h-6 w-6" />} colorClass="text-green-600" />
        <StatCard title={t('revenue.platformCommission')} value={formatNPR(summary?.commission_this_month ?? 0, language as 'en' | 'ne')} icon={<TrendingUp className="h-6 w-6" />} colorClass="text-orange-600" />
      </div>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
        <div className="card">
          <h3 className="mb-4 font-semibold">{t('revenue.daily')} (Last 7 Days)</h3>
          <ResponsiveContainer width="100%" height={200}>
            <BarChart data={summary?.daily_chart ?? []}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="date" tick={{ fontSize: 11 }} />
              <YAxis tick={{ fontSize: 11 }} />
              <Tooltip formatter={(val: number) => formatNPR(val, language as 'en' | 'ne')} />
              <Bar dataKey="revenue" fill="#2563eb" radius={[4, 4, 0, 0]} />
              <Bar dataKey="commission" fill="#f59e0b" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="card">
          <h3 className="mb-4 font-semibold">{t('revenue.byRoute')}</h3>
          <ResponsiveContainer width="100%" height={200}>
            <BarChart data={byRoute} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis type="number" tick={{ fontSize: 11 }} />
              <YAxis type="category" dataKey="route_number" tick={{ fontSize: 11 }} width={40} />
              <Tooltip formatter={(val: number) => formatNPR(val, language as 'en' | 'ne')} />
              <Bar dataKey="revenue" fill="#22c55e" radius={[0, 4, 4, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="card p-0">
        <div className="p-4 border-b">
          <h3 className="font-semibold">Revenue Records</h3>
        </div>
        <Table columns={columns} data={records ?? []} keyExtractor={(r) => r.id} />
      </div>
    </div>
  )
}
