import { ReactNode } from 'react'
import { NavLink, useNavigate } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import {
  LayoutDashboard, Bus, Users, Calendar, Ticket, TrendingUp,
  Wrench, UserCheck, BarChart3, Settings, Menu, X,
  Bell, LogOut, Moon, Sun, Route, MapPin, BookOpen,
} from 'lucide-react'
import { useAuthStore } from '@store/authStore'
import { useUiStore } from '@store/uiStore'
import { LanguageToggle } from '@components/shared/LanguageToggle'
import { CalendarToggle } from '@components/shared/DateDisplay'
import { cn } from '@utils/cn'
import authService from '@services/authService'
import toast from 'react-hot-toast'

const navItems = [
  { to: '/tenant/dashboard', icon: LayoutDashboard, label: 'nav.dashboard' },
  { to: '/tenant/routes', icon: Route, label: 'Routes' },
  { to: '/tenant/stops', icon: MapPin, label: 'Bus Stops' },
  { to: '/tenant/fleet', icon: Bus, label: 'tenant:fleet.title' },
  { to: '/tenant/drivers', icon: UserCheck, label: 'tenant:staff.drivers.title' },
  { to: '/tenant/conductors', icon: Users, label: 'tenant:staff.conductors.title' },
  { to: '/tenant/scheduling', icon: Calendar, label: 'nav.scheduling' },
  { to: '/tenant/ticketing', icon: Ticket, label: 'nav.ticketing' },
  { to: '/tenant/revenue', icon: TrendingUp, label: 'nav.revenue' },
  { to: '/tenant/maintenance', icon: Wrench, label: 'nav.maintenance' },
  { to: '/tenant/analytics', icon: BarChart3, label: 'nav.analytics' },
  { to: '/tenant/accounting', icon: BookOpen, label: 'Accounting' },
  { to: '/tenant/settings', icon: Settings, label: 'nav.settings' },
]

interface TenantLayoutProps {
  children: ReactNode
}

export default function TenantLayout({ children }: TenantLayoutProps) {
  const { t } = useTranslation(['common', 'tenant'])
  const { user, logout: storeLogout, refreshToken } = useAuthStore()
  const { sidebarOpen, toggleSidebar, theme, toggleTheme } = useUiStore()
  const navigate = useNavigate()

  const handleLogout = async () => {
    try {
      if (refreshToken) await authService.logout(refreshToken)
    } catch {}
    storeLogout()
    navigate('/login')
    toast.success('Logged out successfully')
  }

  return (
    <div className={cn('flex min-h-screen', theme === 'dark' ? 'dark' : '')}>
      {/* Sidebar */}
      <aside
        className={cn(
          'sidebar z-40 transition-transform duration-200',
          !sidebarOpen && '-translate-x-full'
        )}
      >
        {/* Logo */}
        <div className="flex h-[var(--header-height)] items-center gap-3 border-b border-gray-200 px-4 dark:border-gray-700">
          <div className="flex h-9 w-9 items-center justify-center rounded-xl bg-primary-600 text-white">
            <Bus className="h-5 w-5" />
          </div>
          <div className="min-w-0">
            <p className="truncate text-sm font-bold text-gray-900 dark:text-white">
              {user?.tenantSchema?.replace(/_/g, ' ').toUpperCase() ?? 'Operator'}
            </p>
            <p className="text-xs text-gray-400">{user?.role?.replace(/_/g, ' ')}</p>
          </div>
        </div>

        {/* Nav */}
        <nav className="flex-1 space-y-0.5 p-3 overflow-y-auto">
          {navItems.map((item) => (
            <NavLink
              key={item.to}
              to={item.to}
              className={({ isActive }) =>
                cn(
                  'flex items-center gap-3 rounded-xl px-3 py-2 text-sm font-medium',
                  'transition-colors duration-150',
                  isActive
                    ? 'bg-primary-50 text-primary-700 dark:bg-primary-900/20 dark:text-primary-300'
                    : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900 dark:text-gray-400 dark:hover:bg-gray-800 dark:hover:text-gray-100'
                )
              }
            >
              <item.icon className="h-4 w-4 flex-shrink-0" />
              <span>{item.label.includes(':') ? t(item.label) : t(item.label)}</span>
            </NavLink>
          ))}
        </nav>

        {/* User info */}
        <div className="border-t border-gray-200 p-4 dark:border-gray-700">
          <div className="flex items-center gap-3">
            <div className="flex h-8 w-8 items-center justify-center rounded-full bg-primary-100 text-primary-700 text-xs font-bold dark:bg-primary-900 dark:text-primary-300">
              {user?.fullName.charAt(0)}
            </div>
            <div className="flex-1 min-w-0">
              <p className="truncate text-xs font-medium text-gray-900 dark:text-white">
                {user?.fullName}
              </p>
              <p className="truncate text-xs text-gray-400">{user?.email}</p>
            </div>
            <button
              onClick={handleLogout}
              className="rounded-lg p-1 text-gray-400 hover:bg-gray-100 hover:text-red-600 dark:hover:bg-gray-800"
            >
              <LogOut className="h-4 w-4" />
            </button>
          </div>
        </div>
      </aside>

      {/* Main */}
      <div className={cn('flex-1 flex flex-col', sidebarOpen && 'lg:ml-[var(--sidebar-width)]')}>
        {/* Header */}
        <header className="sticky top-0 z-30 flex h-[var(--header-height)] items-center gap-4 border-b border-gray-200 bg-white/80 px-4 backdrop-blur-sm dark:border-gray-700 dark:bg-gray-900/80">
          <button
            onClick={toggleSidebar}
            className="rounded-lg p-2 text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800"
          >
            {sidebarOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
          </button>
          <div className="flex-1" />
          <CalendarToggle />
          <LanguageToggle />
          <button onClick={toggleTheme} className="rounded-lg p-2 text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800">
            {theme === 'dark' ? <Sun className="h-5 w-5" /> : <Moon className="h-5 w-5" />}
          </button>
          <button className="relative rounded-lg p-2 text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800">
            <Bell className="h-5 w-5" />
          </button>
        </header>

        {/* Page content */}
        <main className="flex-1 p-6">
          {children}
        </main>
      </div>

      {sidebarOpen && (
        <div className="fixed inset-0 z-30 bg-black/40 lg:hidden" onClick={toggleSidebar} />
      )}
    </div>
  )
}
