/**
 * RoutesPage — draw a route on the map by clicking waypoints, then name & save it.
 */
import { useState, useCallback } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { Plus, Search, MapPin, Clock, Ruler, Trash2, Undo2, Map } from 'lucide-react'
import { MapContainer, TileLayer, Polyline, useMapEvents, Marker, Popup } from 'react-leaflet'
import L from 'leaflet'
import 'leaflet/dist/leaflet.css'
import { Button } from '@components/shared/Button'
import { Input } from '@components/shared/Input'
import { Table, Column, Pagination } from '@components/shared/Table'
import { Badge } from '@components/shared/Badge'
import { Modal } from '@components/shared/Modal'
import { usePagination } from '@hooks/usePagination'
import apiClient from '@services/api'
import toast from 'react-hot-toast'
import { useForm } from 'react-hook-form'
import { cn } from '@utils/cn'

// Fix Leaflet icon
delete (L.Icon.Default.prototype as { _getIconUrl?: unknown })._getIconUrl
L.Icon.Default.mergeOptions({
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
})

const waypointIcon = (label: string) =>
  L.divIcon({
    html: `<div style="
      background:#2563eb;color:#fff;border-radius:50%;
      width:26px;height:26px;display:flex;align-items:center;
      justify-content:center;font-size:11px;font-weight:700;
      box-shadow:0 2px 6px rgba(0,0,0,.3);border:2px solid #fff;
    ">${label}</div>`,
    className: '',
    iconSize: [26, 26],
    iconAnchor: [13, 13],
  })

const KATHMANDU: [number, number] = [27.7172, 85.3240]

// ── Haversine distance between two lat/lng points (km) ──────────────────────
function haversine([lat1, lng1]: [number, number], [lat2, lng2]: [number, number]) {
  const R = 6371
  const dLat = ((lat2 - lat1) * Math.PI) / 180
  const dLng = ((lng2 - lng1) * Math.PI) / 180
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos((lat1 * Math.PI) / 180) *
      Math.cos((lat2 * Math.PI) / 180) *
      Math.sin(dLng / 2) ** 2
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
}

function totalDistance(pts: [number, number][]) {
  let d = 0
  for (let i = 1; i < pts.length; i++) d += haversine(pts[i - 1], pts[i])
  return d
}

// ── Map click handler component ──────────────────────────────────────────────
function ClickHandler({ onMapClick }: { onMapClick: (lat: number, lng: number) => void }) {
  useMapEvents({
    click(e) {
      onMapClick(e.latlng.lat, e.latlng.lng)
    },
  })
  return null
}

// ── Route interface ──────────────────────────────────────────────────────────
interface Route {
  id: string
  route_code: string
  name_en: string
  name_ne: string
  distance_km: number
  status: string
  geojson_path: string
  route_stops: { id: string; sequence_no: number; stop_detail: { name_en: string } }[]
}

interface RouteForm {
  route_code: string
  name_en: string
  name_ne: string
  base_fare: string
}

// ════════════════════════════════════════════════════════════════════════════════
export default function RoutesPage() {
  const qc = useQueryClient()
  const [search, setSearch] = useState('')
  const [showCreate, setShowCreate] = useState(false)
  const [totalCount, setTotalCount] = useState(0)
  const pagination = usePagination(totalCount)

  // Drawn waypoints for new route
  const [waypoints, setWaypoints] = useState<[number, number][]>([])

  const { data, isLoading } = useQuery({
    queryKey: ['routes', pagination.page, search],
    queryFn: async () => {
      const { data } = await apiClient.get('/platform/routes/', {
        params: { ...pagination.queryParams, ...(search && { search }) },
      })
      setTotalCount(data.meta?.total_count ?? data.data?.count ?? 0)
      return data.data?.results ?? []
    },
  })

  const { register, handleSubmit, reset, formState: { errors } } = useForm<RouteForm>()

  const createMutation = useMutation({
    mutationFn: (d: RouteForm) => {
      const dist = parseFloat(totalDistance(waypoints).toFixed(2))
      const geojson = waypoints.length >= 2
        ? JSON.stringify({
            type: 'Feature',
            geometry: {
              type: 'LineString',
              coordinates: waypoints.map(([lat, lng]) => [lng, lat]),
            },
          })
        : ''
      return apiClient.post('/platform/routes/', {
        route_code: d.route_code,
        name_en: d.name_en,
        name_ne: d.name_ne || '',
        distance_km: dist,
        geojson_path: geojson,
        route_type: 'EXCLUSIVE',
        status: 'DRAFT',
      }).then((r) => {
        if (!r.data.success) throw new Error(r.data.message)
        return r.data
      })
    },
    onSuccess: () => {
      toast.success('Route created!')
      setShowCreate(false)
      setWaypoints([])
      reset()
      qc.invalidateQueries({ queryKey: ['routes'] })
    },
    onError: (err: Error) => toast.error(err.message || 'Failed to create route'),
  })

  const handleMapClick = useCallback((lat: number, lng: number) => {
    setWaypoints((prev) => [...prev, [lat, lng]])
  }, [])

  const handleUndo = () => setWaypoints((prev) => prev.slice(0, -1))
  const handleClear = () => setWaypoints([])

  const distKm = totalDistance(waypoints).toFixed(2)

  const columns: Column<Route>[] = [
    {
      key: 'route_code',
      header: 'Code',
      render: (r) => <span className="font-mono font-bold text-primary-600">{r.route_code}</span>,
    },
    {
      key: 'name_en',
      header: 'Route Name',
      render: (r) => (
        <div>
          <p className="font-medium text-gray-900">{r.name_en}</p>
          {r.name_ne && <p className="text-xs text-gray-400">{r.name_ne}</p>}
        </div>
      ),
    },
    {
      key: 'route_stops',
      header: 'Stops',
      render: (r) => (
        <div className="flex items-center gap-1 text-sm">
          <MapPin className="h-3.5 w-3.5 text-gray-400" />
          {r.route_stops?.length ?? 0} stops
        </div>
      ),
    },
    {
      key: 'distance_km',
      header: 'Distance',
      render: (r) => (
        <div className="flex items-center gap-1 text-sm">
          <Ruler className="h-3.5 w-3.5 text-gray-400" />
          {r.distance_km} km
        </div>
      ),
    },
    {
      key: 'geojson_path',
      header: 'Path',
      render: (r) => r.geojson_path
        ? <Badge variant="success">Mapped</Badge>
        : <Badge variant="neutral">No map</Badge>,
    },
    {
      key: 'status',
      header: 'Status',
      render: (r) => (
        <Badge variant={r.status === 'APPROVED' ? 'success' : r.status === 'DRAFT' ? 'neutral' : 'warning'} dot>
          {r.status}
        </Badge>
      ),
    },
  ]

  return (
    <div className="space-y-6">
      <div className="page-header">
        <div>
          <h1 className="page-title">Routes</h1>
          <p className="page-subtitle">Draw and manage transit routes on the map</p>
        </div>
        <Button leftIcon={<Plus className="h-4 w-4" />} onClick={() => setShowCreate(true)}>
          Add Route
        </Button>
      </div>

      <Input
        placeholder="Search by route code or name..."
        leftAddon={<Search className="h-4 w-4" />}
        value={search}
        onChange={(e) => setSearch(e.target.value)}
        className="max-w-sm"
      />

      <div className="card p-0">
        <Table columns={columns} data={data ?? []} keyExtractor={(r) => r.id} loading={isLoading} />
        <Pagination
          page={pagination.page} totalPages={pagination.totalPages}
          totalCount={totalCount} pageSize={pagination.pageSize}
          onPageChange={pagination.setPage}
        />
      </div>

      {/* ── Add Route Modal — map draw ──────────────────────────────────────── */}
      <Modal
        open={showCreate}
        onClose={() => { setShowCreate(false); setWaypoints([]); reset() }}
        title="Add Route"
        size="xl"
      >
        <div className="flex h-[620px] flex-col">
          {/* Top form strip */}
          <form
            id="route-form"
            onSubmit={handleSubmit((d) => createMutation.mutate(d))}
            className="shrink-0 border-b border-gray-100 bg-gray-50 px-6 py-4"
          >
            <div className="grid grid-cols-2 gap-4 sm:grid-cols-4">
              <Input
                label="Route Code *"
                placeholder="e.g. 23, 37A"
                error={errors.route_code?.message}
                {...register('route_code', { required: 'Required' })}
              />
              <div className="sm:col-span-2">
                <Input
                  label="Route Name (English) *"
                  placeholder="e.g. Ratnapark — Kalanki"
                  error={errors.name_en?.message}
                  {...register('name_en', { required: 'Required' })}
                />
              </div>
              <Input
                label="Nepali Name"
                placeholder="e.g. रत्नपार्क — कलंकी"
                {...register('name_ne')}
              />
            </div>
          </form>

          {/* Map + sidebar */}
          <div className="flex flex-1 overflow-hidden">
            {/* Map */}
            <div className="relative flex-1">
              <MapContainer
                center={KATHMANDU}
                zoom={12}
                style={{ height: '100%', width: '100%' }}
                className="z-0"
              >
                <TileLayer
                  attribution='© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                  url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                />
                <ClickHandler onMapClick={handleMapClick} />

                {/* Polyline */}
                {waypoints.length >= 2 && (
                  <Polyline
                    positions={waypoints}
                    pathOptions={{ color: '#2563eb', weight: 4, opacity: 0.85 }}
                  />
                )}

                {/* Waypoint markers */}
                {waypoints.map((pt, i) => (
                  <Marker key={i} position={pt} icon={waypointIcon(String(i + 1))}>
                    <Popup>
                      Point {i + 1}<br />
                      {pt[0].toFixed(5)}, {pt[1].toFixed(5)}
                    </Popup>
                  </Marker>
                ))}
              </MapContainer>

              {/* Map instruction overlay */}
              <div className="absolute top-3 left-1/2 z-10 -translate-x-1/2 rounded-xl bg-white/90 px-4 py-2 shadow text-sm font-medium text-gray-700 backdrop-blur-sm whitespace-nowrap">
                <Map className="inline h-4 w-4 mr-1.5 text-primary-500" />
                Click on the map to add route waypoints
              </div>
            </div>

            {/* Right sidebar */}
            <div className="flex w-64 shrink-0 flex-col border-l border-gray-100 bg-white p-4">
              <div className="mb-3 flex items-center justify-between">
                <p className="text-sm font-semibold text-gray-700">Waypoints</p>
                <div className="flex gap-1">
                  <button
                    type="button"
                    onClick={handleUndo}
                    disabled={waypoints.length === 0}
                    title="Undo last point"
                    className={cn(
                      'rounded-lg p-1.5 text-gray-500 hover:bg-gray-100',
                      waypoints.length === 0 && 'opacity-30 cursor-not-allowed'
                    )}
                  >
                    <Undo2 className="h-4 w-4" />
                  </button>
                  <button
                    type="button"
                    onClick={handleClear}
                    disabled={waypoints.length === 0}
                    title="Clear all"
                    className={cn(
                      'rounded-lg p-1.5 text-red-400 hover:bg-red-50',
                      waypoints.length === 0 && 'opacity-30 cursor-not-allowed'
                    )}
                  >
                    <Trash2 className="h-4 w-4" />
                  </button>
                </div>
              </div>

              {/* Stats */}
              <div className="mb-3 rounded-lg bg-primary-50 p-3 space-y-1.5">
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">Points</span>
                  <span className="font-semibold text-primary-700">{waypoints.length}</span>
                </div>
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">Distance</span>
                  <span className="font-semibold text-primary-700">{distKm} km</span>
                </div>
              </div>

              {/* Waypoints list */}
              <div className="flex-1 overflow-y-auto space-y-1 text-xs">
                {waypoints.length === 0 ? (
                  <p className="text-center text-gray-400 mt-6 italic text-xs">
                    Click on the map to start drawing the route
                  </p>
                ) : (
                  waypoints.map((pt, i) => (
                    <div
                      key={i}
                      className={cn(
                        'flex items-center gap-2 rounded-lg px-2.5 py-1.5',
                        i === 0 ? 'bg-green-50' : i === waypoints.length - 1 ? 'bg-red-50' : 'bg-gray-50'
                      )}
                    >
                      <span className={cn(
                        'flex h-5 w-5 shrink-0 items-center justify-center rounded-full text-[10px] font-bold text-white',
                        i === 0 ? 'bg-green-500' : i === waypoints.length - 1 ? 'bg-red-500' : 'bg-blue-500'
                      )}>
                        {i + 1}
                      </span>
                      <div>
                        <p className="font-medium text-gray-700">
                          {i === 0 ? 'Start' : i === waypoints.length - 1 ? 'End' : `Point ${i + 1}`}
                        </p>
                        <p className="text-gray-400">{pt[0].toFixed(4)}, {pt[1].toFixed(4)}</p>
                      </div>
                    </div>
                  ))
                )}
              </div>

              {/* Save button */}
              <div className="mt-4 border-t border-gray-100 pt-4 space-y-2">
                {waypoints.length < 2 && waypoints.length > 0 && (
                  <p className="text-xs text-amber-600 text-center">
                    Add at least 2 points to draw a route
                  </p>
                )}
                <Button
                  type="submit"
                  form="route-form"
                  className="w-full"
                  loading={createMutation.isPending}
                  disabled={waypoints.length < 2}
                  leftIcon={<Plus className="h-4 w-4" />}
                >
                  Save Route
                </Button>
                <Button
                  variant="secondary"
                  type="button"
                  className="w-full"
                  onClick={() => { setShowCreate(false); setWaypoints([]); reset() }}
                >
                  Cancel
                </Button>
              </div>
            </div>
          </div>
        </div>
      </Modal>
    </div>
  )
}
