/**
 * StopsPage — select a route from dropdown, see its path on the map,
 * click to place stops, fill details, and save.
 */
import { useState, useCallback } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { Plus, Search, MapPin, X, Navigation } from 'lucide-react'
import { MapContainer, TileLayer, Polyline, Marker, Popup, useMapEvents } from 'react-leaflet'
import L from 'leaflet'
import 'leaflet/dist/leaflet.css'
import { Button } from '@components/shared/Button'
import { Input } from '@components/shared/Input'
import { Table, Column, Pagination } from '@components/shared/Table'
import { Badge } from '@components/shared/Badge'
import { Modal } from '@components/shared/Modal'
import { usePagination } from '@hooks/usePagination'
import apiClient from '@services/api'
import toast from 'react-hot-toast'
import { useForm } from 'react-hook-form'
import { cn } from '@utils/cn'

// Fix Leaflet icons
delete (L.Icon.Default.prototype as { _getIconUrl?: unknown })._getIconUrl
L.Icon.Default.mergeOptions({
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
})

const stopPinIcon = (seq: number, isTerminal = false) =>
  L.divIcon({
    html: `<div style="
      background:${isTerminal ? '#16a34a' : '#dc2626'};
      color:#fff;border-radius:50%;width:28px;height:28px;
      display:flex;align-items:center;justify-content:center;
      font-size:11px;font-weight:700;box-shadow:0 2px 6px rgba(0,0,0,.35);
      border:2px solid #fff;
    ">${seq}</div>`,
    className: '',
    iconSize: [28, 28],
    iconAnchor: [14, 14],
  })

const KATHMANDU: [number, number] = [27.7172, 85.3240]

// ── Parse GeoJSON LineString → Leaflet positions ─────────────────────────────
function parseRouteGeoJSON(geojson: string): [number, number][] {
  try {
    const parsed = JSON.parse(geojson)
    const coords: [number, number][] =
      parsed?.geometry?.coordinates ?? parsed?.coordinates ?? []
    return coords.map(([lng, lat]: [number, number]) => [lat, lng])
  } catch {
    return []
  }
}

// ── Types ────────────────────────────────────────────────────────────────────
interface Route {
  id: string
  route_code: string
  name_en: string
  geojson_path: string
  route_stops: { id: string; sequence_no: number; stop_detail: { name_en: string; latitude: number; longitude: number } }[]
}

interface Stop {
  id: string
  stop_code: string
  name_en: string
  name_ne: string
  latitude: number
  longitude: number
  status: string
}

interface PendingStop {
  lat: number
  lng: number
  name_en: string
  name_ne: string
  is_terminal: boolean
}

interface StopForm {
  name_en: string
  name_ne: string
  is_terminal: boolean
}

// ── Click handler ─────────────────────────────────────────────────────────────
function MapClickHandler({ enabled, onClick }: { enabled: boolean; onClick: (lat: number, lng: number) => void }) {
  useMapEvents({
    click(e) {
      if (enabled) onClick(e.latlng.lat, e.latlng.lng)
    },
  })
  return null
}

// ════════════════════════════════════════════════════════════════════════════════
export default function StopsPage() {
  const qc = useQueryClient()
  const [search, setSearch] = useState('')
  const [showCreate, setShowCreate] = useState(false)
  const [totalCount, setTotalCount] = useState(0)
  const [selectedRouteId, setSelectedRouteId] = useState('')
  const [pendingStop, setPendingStop] = useState<PendingStop | null>(null)
  const [savedStops, setSavedStops] = useState<(PendingStop & { seq: number })[]>([])
  const pagination = usePagination(totalCount)

  const { data: stops = [], isLoading } = useQuery({
    queryKey: ['stops', pagination.page, search],
    queryFn: async () => {
      const { data } = await apiClient.get('/platform/stops/', {
        params: { ...pagination.queryParams, ...(search && { search }) },
      })
      setTotalCount(data.meta?.total_count ?? data.data?.count ?? 0)
      return data.data?.results ?? []
    },
  })

  // All routes for dropdown
  const { data: routes = [] } = useQuery({
    queryKey: ['routes-dropdown'],
    queryFn: async () => {
      const { data } = await apiClient.get('/platform/routes/?page_size=200')
      return (data.data?.results ?? []) as Route[]
    },
    staleTime: 5 * 60 * 1000,
  })

  const selectedRoute = routes.find((r) => r.id === selectedRouteId)
  const routePath = selectedRoute?.geojson_path ? parseRouteGeoJSON(selectedRoute.geojson_path) : []

  const { register, handleSubmit, reset, formState: { errors } } = useForm<StopForm>()

  // Called when user clicks the map
  const handleMapClick = useCallback((lat: number, lng: number) => {
    if (!pendingStop) {
      setPendingStop({ lat, lng, name_en: '', name_ne: '', is_terminal: false })
    }
  }, [pendingStop])

  const addStopMutation = useMutation({
    mutationFn: async (form: StopForm) => {
      if (!pendingStop || !selectedRouteId) throw new Error('No stop placed or route selected')
      const res = await apiClient.post(`/platform/routes/${selectedRouteId}/add-stop/`, {
        name_en: form.name_en,
        name_ne: form.name_ne || '',
        latitude: pendingStop.lat,
        longitude: pendingStop.lng,
        is_terminal: form.is_terminal,
      })
      if (!res.data.success) throw new Error(res.data.message)
      return { ...res.data.data, formData: form }
    },
    onSuccess: (data) => {
      toast.success(`Stop "${data.formData.name_en}" added!`)
      setSavedStops((prev) => [...prev, {
        ...pendingStop!,
        name_en: data.formData.name_en,
        name_ne: data.formData.name_ne,
        is_terminal: data.formData.is_terminal,
        seq: (prev.length + 1),
      }])
      setPendingStop(null)
      reset()
      qc.invalidateQueries({ queryKey: ['stops'] })
      qc.invalidateQueries({ queryKey: ['routes'] })
    },
    onError: (err: Error) => toast.error(err.message),
  })

  const handleCloseModal = () => {
    setShowCreate(false)
    setPendingStop(null)
    setSavedStops([])
    setSelectedRouteId('')
    reset()
  }

  // Compute center for map — use route path center or Kathmandu default
  const mapCenter: [number, number] = routePath.length > 0
    ? [
        routePath.reduce((s, p) => s + p[0], 0) / routePath.length,
        routePath.reduce((s, p) => s + p[1], 0) / routePath.length,
      ]
    : KATHMANDU

  const columns: Column<Stop>[] = [
    {
      key: 'name_en',
      header: 'Stop Name',
      render: (s) => (
        <div className="flex items-center gap-2">
          <MapPin className="h-4 w-4 text-red-500 shrink-0" />
          <div>
            <p className="font-medium text-gray-900">{s.name_en}</p>
            {s.name_ne && <p className="text-xs text-gray-400">{s.name_ne}</p>}
          </div>
        </div>
      ),
    },
    { key: 'stop_code', header: 'Code', render: (s) => <code className="text-xs text-gray-600">{s.stop_code}</code> },
    {
      key: 'latitude',
      header: 'Coordinates',
      render: (s) => (
        <code className="text-xs text-gray-600">
          {Number(s.latitude).toFixed(5)}, {Number(s.longitude).toFixed(5)}
        </code>
      ),
    },
    {
      key: 'status',
      header: 'Status',
      render: (s) => (
        <Badge variant={s.status === 'ACTIVE' ? 'success' : 'neutral'} dot>{s.status}</Badge>
      ),
    },
  ]

  return (
    <div className="space-y-6">
      <div className="page-header">
        <div>
          <h1 className="page-title">Bus Stops</h1>
          <p className="page-subtitle">Place stops on the map route-by-route</p>
        </div>
        <Button leftIcon={<Plus className="h-4 w-4" />} onClick={() => setShowCreate(true)}>
          Add Stop
        </Button>
      </div>

      <Input
        placeholder="Search by stop name or code..."
        leftAddon={<Search className="h-4 w-4" />}
        value={search}
        onChange={(e) => setSearch(e.target.value)}
        className="max-w-sm"
      />

      <div className="card p-0">
        <Table columns={columns} data={stops} keyExtractor={(s) => s.id} loading={isLoading} />
        <Pagination
          page={pagination.page} totalPages={pagination.totalPages}
          totalCount={totalCount} pageSize={pagination.pageSize}
          onPageChange={pagination.setPage}
        />
      </div>

      {/* ── Add Stop Modal ──────────────────────────────────────────────────── */}
      <Modal open={showCreate} onClose={handleCloseModal} title="Add Bus Stop" size="xl">
        <div className="flex h-[620px] flex-col">

          {/* Route selector strip */}
          <div className="shrink-0 border-b border-gray-100 bg-gray-50 px-6 py-3">
            <div className="flex items-center gap-4">
              <div className="w-80">
                <label className="mb-1 block text-xs font-semibold uppercase tracking-wide text-gray-500">
                  Select Route *
                </label>
                <select
                  value={selectedRouteId}
                  onChange={(e) => {
                    setSelectedRouteId(e.target.value)
                    setPendingStop(null)
                    setSavedStops([])
                    reset()
                  }}
                  className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm
                             focus:border-primary-500 focus:outline-none focus:ring-1 focus:ring-primary-500"
                >
                  <option value="">— Choose a route to add stops —</option>
                  {routes.map((r) => (
                    <option key={r.id} value={r.id}>
                      {r.route_code} — {r.name_en}
                    </option>
                  ))}
                </select>
              </div>
              {selectedRoute && (
                <div className="flex items-center gap-2 rounded-lg border border-blue-200 bg-blue-50 px-3 py-2">
                  <Navigation className="h-4 w-4 text-blue-500" />
                  <span className="text-sm font-medium text-blue-700">{selectedRoute.name_en}</span>
                  {routePath.length > 0 && (
                    <Badge variant="info" className="ml-1">Route visible on map</Badge>
                  )}
                </div>
              )}
            </div>
            {selectedRouteId && !pendingStop && (
              <p className="mt-2 text-xs text-amber-600 font-medium">
                📍 Click anywhere on the map to place a new bus stop
              </p>
            )}
          </div>

          {/* Map + form panel */}
          <div className="flex flex-1 overflow-hidden">
            {/* Map */}
            <div className="relative flex-1">
              <MapContainer
                key={selectedRouteId || 'default'}
                center={mapCenter}
                zoom={routePath.length > 0 ? 13 : 12}
                style={{ height: '100%', width: '100%' }}
                className="z-0"
              >
                <TileLayer
                  attribution='© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                  url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                />
                <MapClickHandler
                  enabled={!!selectedRouteId && !pendingStop}
                  onClick={handleMapClick}
                />

                {/* Route polyline */}
                {routePath.length >= 2 && (
                  <Polyline
                    positions={routePath}
                    pathOptions={{ color: '#2563eb', weight: 4, opacity: 0.7, dashArray: '8 4' }}
                  />
                )}

                {/* Existing route stops */}
                {selectedRoute?.route_stops?.map((rs) => (
                  <Marker
                    key={rs.id}
                    position={[rs.stop_detail.latitude, rs.stop_detail.longitude]}
                    icon={stopPinIcon(rs.sequence_no)}
                  >
                    <Popup>
                      <div className="text-sm">
                        <p className="font-semibold">#{rs.sequence_no} {rs.stop_detail.name_en}</p>
                        <p className="text-xs text-gray-400">Existing stop</p>
                      </div>
                    </Popup>
                  </Marker>
                ))}

                {/* Newly saved stops in this session */}
                {savedStops.map((s, i) => (
                  <Marker
                    key={`new-${i}`}
                    position={[s.lat, s.lng]}
                    icon={stopPinIcon(savedStops.length - i + (selectedRoute?.route_stops?.length ?? 0), s.is_terminal)}
                  >
                    <Popup>
                      <p className="text-sm font-semibold text-green-700">✓ {s.name_en}</p>
                      <p className="text-xs text-gray-400">Just added</p>
                    </Popup>
                  </Marker>
                ))}

                {/* Pending stop pin */}
                {pendingStop && (
                  <Marker position={[pendingStop.lat, pendingStop.lng]}>
                    <Popup>Fill in the form →</Popup>
                  </Marker>
                )}
              </MapContainer>

              {/* No route selected overlay */}
              {!selectedRouteId && (
                <div className="absolute inset-0 z-10 flex items-center justify-center bg-white/60 backdrop-blur-sm">
                  <div className="rounded-xl border border-gray-200 bg-white px-6 py-5 shadow-lg text-center">
                    <MapPin className="mx-auto mb-2 h-8 w-8 text-gray-300" />
                    <p className="font-semibold text-gray-600">Select a route first</p>
                    <p className="mt-1 text-sm text-gray-400">The route path will appear on the map</p>
                  </div>
                </div>
              )}
            </div>

            {/* Right: Stop detail form */}
            <div className="flex w-72 shrink-0 flex-col border-l border-gray-100 bg-white p-5">
              {!pendingStop ? (
                <div className="flex flex-1 flex-col items-center justify-center text-center gap-3">
                  <div className="rounded-full bg-gray-100 p-4">
                    <MapPin className="h-7 w-7 text-gray-400" />
                  </div>
                  <div>
                    <p className="font-semibold text-gray-600">
                      {selectedRouteId ? 'Click map to place a stop' : 'Select a route first'}
                    </p>
                    <p className="mt-1 text-xs text-gray-400">
                      {selectedRouteId
                        ? 'Then fill in the stop details here'
                        : 'The map will show the route path'}
                    </p>
                  </div>

                  {/* Summary of added stops */}
                  {savedStops.length > 0 && (
                    <div className="mt-4 w-full rounded-xl border border-green-200 bg-green-50 p-3">
                      <p className="text-xs font-semibold text-green-700 mb-2">
                        ✓ {savedStops.length} stop{savedStops.length > 1 ? 's' : ''} added this session
                      </p>
                      <div className="space-y-1">
                        {savedStops.map((s, i) => (
                          <div key={i} className="flex items-center gap-1.5 text-xs text-green-700">
                            <span className="h-4 w-4 rounded-full bg-green-500 text-white text-[9px] flex items-center justify-center font-bold shrink-0">
                              {i + 1}
                            </span>
                            <span className="truncate">{s.name_en}</span>
                            {s.is_terminal && <Badge variant="info" className="text-[9px] py-0">T</Badge>}
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              ) : (
                <>
                  <div className="mb-4 flex items-center justify-between">
                    <p className="text-sm font-semibold text-gray-800">New Stop</p>
                    <button
                      type="button"
                      onClick={() => { setPendingStop(null); reset() }}
                      className="rounded-lg p-1 text-gray-400 hover:bg-gray-100"
                    >
                      <X className="h-4 w-4" />
                    </button>
                  </div>

                  {/* Coordinates preview */}
                  <div className="mb-3 rounded-lg bg-blue-50 px-3 py-2 text-xs text-blue-700">
                    📍 {pendingStop.lat.toFixed(5)}, {pendingStop.lng.toFixed(5)}
                  </div>

                  <form
                    onSubmit={handleSubmit((d) => addStopMutation.mutate(d))}
                    className="flex flex-1 flex-col gap-3"
                  >
                    <Input
                      label="Stop Name (English) *"
                      placeholder="e.g. Kalanki Chowk"
                      error={errors.name_en?.message}
                      {...register('name_en', { required: 'Stop name is required' })}
                    />
                    <Input
                      label="Stop Name (Nepali)"
                      placeholder="e.g. कलंकी चोक"
                      {...register('name_ne')}
                    />
                    <div className="flex items-center gap-2 rounded-lg border border-gray-200 px-3 py-2.5">
                      <input
                        type="checkbox"
                        id="is_terminal"
                        className="h-4 w-4 rounded border-gray-300 text-green-600"
                        {...register('is_terminal')}
                      />
                      <label htmlFor="is_terminal" className="text-sm text-gray-700 cursor-pointer">
                        Terminal Stop
                        <span className="block text-xs text-gray-400">Start or end of route</span>
                      </label>
                    </div>

                    <div className="mt-auto pt-3 border-t border-gray-100 space-y-2">
                      <Button
                        type="submit"
                        className="w-full"
                        loading={addStopMutation.isPending}
                        leftIcon={<Plus className="h-4 w-4" />}
                      >
                        Add Stop
                      </Button>
                      <Button
                        type="button"
                        variant="secondary"
                        className="w-full"
                        onClick={() => { setPendingStop(null); reset() }}
                      >
                        Cancel
                      </Button>
                    </div>
                  </form>
                </>
              )}
            </div>
          </div>
        </div>
      </Modal>
    </div>
  )
}
