import { useForm } from 'react-hook-form'
import { useMutation, useQuery } from '@tanstack/react-query'
import { Save, Building2, Bell } from 'lucide-react'
import { Button } from '@components/shared/Button'
import { Input } from '@components/shared/Input'
import { LanguageToggle } from '@components/shared/LanguageToggle'
import { CalendarToggle } from '@components/shared/DateDisplay'
import apiClient from '@services/api'
import authService from '@services/authService'
import toast from 'react-hot-toast'
import { useUiStore } from '@store/uiStore'

interface CompanyForm {
  name: string
  contact_email: string
  contact_phone: string
  address: string
}

interface PasswordForm {
  old_password: string
  new_password: string
  confirm_password: string
}

export default function TenantSettingsPage() {
  const { language, calendarType } = useUiStore()

  const { data: companyInfo } = useQuery({
    queryKey: ['company-info'],
    queryFn: async () => {
      const { data } = await apiClient.get('/staff/company/')
      return data.data
    },
  })

  const companyForm = useForm<CompanyForm>({ values: companyInfo })

  const companyMutation = useMutation({
    mutationFn: (payload: CompanyForm) =>
      apiClient.patch('/staff/company/', payload).then((r) => r.data),
    onSuccess: () => toast.success('Company info updated!'),
    onError: (err: Error) => toast.error(err.message),
  })

  const { register: regPass, handleSubmit: handlePass, reset: resetPass, watch, formState: { errors } } = useForm<PasswordForm>()

  const passwordMutation = useMutation({
    mutationFn: (data: PasswordForm) => authService.changePassword(data),
    onSuccess: () => {
      toast.success('Password updated!')
      resetPass()
    },
    onError: (err: Error) => toast.error(err.message),
  })

  return (
    <div className="space-y-6">
      <div className="page-header">
        <h1 className="page-title">Settings</h1>
      </div>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
        {/* Company Info */}
        <div className="card">
          <h2 className="mb-4 flex items-center gap-2 font-semibold">
            <Building2 className="h-5 w-5 text-primary-600" />
            Company Information
          </h2>
          <form onSubmit={companyForm.handleSubmit((d) => companyMutation.mutate(d))} className="space-y-4">
            <Input label="Company Name" {...companyForm.register('name')} />
            <Input label="Contact Email" type="email" {...companyForm.register('contact_email')} />
            <Input label="Contact Phone" type="tel" {...companyForm.register('contact_phone')} />
            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700">Address</label>
              <textarea className="w-full rounded-lg border px-3 py-2 text-sm" rows={3} {...companyForm.register('address')} />
            </div>
            <Button type="submit" leftIcon={<Save className="h-4 w-4" />} loading={companyMutation.isPending}>
              Save Changes
            </Button>
          </form>
        </div>

        {/* Display */}
        <div className="card space-y-4">
          <h2 className="font-semibold">Display Preferences</h2>
          <div>
            <label className="mb-2 block text-sm font-medium text-gray-700">Language</label>
            <LanguageToggle />
            <p className="mt-1 text-xs text-gray-400">Current: {language === 'en' ? 'English' : 'नेपाली'}</p>
          </div>
          <div>
            <label className="mb-2 block text-sm font-medium text-gray-700">Calendar</label>
            <CalendarToggle />
            <p className="mt-1 text-xs text-gray-400">Current: {calendarType}</p>
          </div>
        </div>

        {/* Change password */}
        <div className="card">
          <h2 className="mb-4 font-semibold">Change Password</h2>
          <form onSubmit={handlePass((d) => passwordMutation.mutate(d))} className="space-y-4">
            <Input label="Current Password" type="password" required error={errors.old_password?.message} {...regPass('old_password', { required: true })} />
            <Input label="New Password" type="password" required error={errors.new_password?.message}
              {...regPass('new_password', { required: true, minLength: { value: 8, message: 'Min 8 chars' } })} />
            <Input label="Confirm Password" type="password" required error={errors.confirm_password?.message}
              {...regPass('confirm_password', { required: true, validate: (v) => v === watch('new_password') || 'Passwords do not match' })} />
            <Button type="submit" loading={passwordMutation.isPending}>Update Password</Button>
          </form>
        </div>

        {/* Notifications */}
        <div className="card">
          <h2 className="mb-4 flex items-center gap-2 font-semibold">
            <Bell className="h-5 w-5 text-primary-600" />
            Notifications
          </h2>
          {[
            'Document expiry alerts',
            'Low stock alerts',
            'Trip cancellation alerts',
            'Maintenance reminders',
            'Revenue reports',
          ].map((label) => (
            <label key={label} className="flex items-center justify-between py-2 border-b last:border-0">
              <span className="text-sm text-gray-700">{label}</span>
              <input type="checkbox" defaultChecked className="h-4 w-4 rounded border-gray-300 text-primary-600" />
            </label>
          ))}
        </div>
      </div>
    </div>
  )
}
