import { useQuery } from '@tanstack/react-query'
import { useTranslation } from 'react-i18next'
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LineChart, Line } from 'recharts'
import { StatCard } from '@components/shared/StatCard'
import { Bus, Users, TrendingUp, Clock } from 'lucide-react'
import apiClient from '@services/api'
import { formatNPR } from '@utils/nepaliDate'
import { useUiStore } from '@store/uiStore'

export default function TenantAnalyticsPage() {
  const { t } = useTranslation('tenant')
  const { language } = useUiStore()

  const { data: kpis } = useQuery({
    queryKey: ['tenant-kpis'],
    queryFn: async () => {
      const { data } = await apiClient.get('/analytics/kpis/')
      return data.data
    },
  })

  const { data: tripTrend } = useQuery({
    queryKey: ['trip-trend'],
    queryFn: async () => {
      const { data } = await apiClient.get('/analytics/trips/trend/')
      return data.data ?? []
    },
  })

  return (
    <div className="space-y-6">
      <div className="page-header">
        <h1 className="page-title">{t('analytics.title')}</h1>
      </div>

      {/* KPIs */}
      <div className="grid grid-cols-2 gap-4 lg:grid-cols-4">
        <StatCard
          title={t('analytics.fleetUtilization')}
          value={`${kpis?.fleet_utilization ?? 0}%`}
          icon={<Bus className="h-6 w-6" />}
          trend={kpis?.fleet_util_trend}
        />
        <StatCard
          title={t('analytics.onTimePerformance')}
          value={`${kpis?.on_time_performance ?? 0}%`}
          icon={<Clock className="h-6 w-6" />}
          colorClass="text-green-600"
        />
        <StatCard
          title={t('analytics.passengerCount')}
          value={(kpis?.total_passengers ?? 0).toLocaleString()}
          icon={<Users className="h-6 w-6" />}
          trend={kpis?.passenger_trend}
        />
        <StatCard
          title={t('analytics.revenuePerTrip')}
          value={formatNPR(kpis?.avg_revenue_per_trip ?? 0, language as 'en' | 'ne')}
          icon={<TrendingUp className="h-6 w-6" />}
        />
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
        <div className="card">
          <h3 className="mb-4 font-semibold">Daily Trips (Last 30 Days)</h3>
          <ResponsiveContainer width="100%" height={220}>
            <LineChart data={tripTrend}>
              <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
              <XAxis dataKey="date" tick={{ fontSize: 10 }} />
              <YAxis tick={{ fontSize: 11 }} />
              <Tooltip />
              <Line type="monotone" dataKey="trips" stroke="#2563eb" strokeWidth={2} dot={false} />
              <Line type="monotone" dataKey="passengers" stroke="#22c55e" strokeWidth={2} dot={false} />
            </LineChart>
          </ResponsiveContainer>
        </div>

        <div className="card">
          <h3 className="mb-4 font-semibold">{t('analytics.topRoutes')}</h3>
          <ResponsiveContainer width="100%" height={220}>
            <BarChart data={kpis?.top_routes ?? []} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis type="number" tick={{ fontSize: 11 }} />
              <YAxis type="category" dataKey="route" tick={{ fontSize: 11 }} width={35} />
              <Tooltip />
              <Bar dataKey="passengers" fill="#8b5cf6" radius={[0, 4, 4, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Summary stats */}
      <div className="card">
        <h3 className="mb-4 font-semibold">Performance Summary</h3>
        <div className="grid grid-cols-2 gap-6 sm:grid-cols-4 text-center">
          {[
            { label: t('analytics.fuelEfficiency'), value: `${kpis?.fuel_efficiency ?? 0} km/L` },
            { label: t('analytics.breakdown'), value: `${kpis?.breakdown_rate ?? 0}%` },
            { label: t('analytics.averageSpeed'), value: `${kpis?.avg_speed ?? 0} km/h` },
            { label: 'Total Distance', value: `${(kpis?.total_distance ?? 0).toLocaleString()} km` },
          ].map((stat) => (
            <div key={stat.label}>
              <p className="text-2xl font-bold text-gray-900 dark:text-white">{stat.value}</p>
              <p className="mt-1 text-sm text-gray-500">{stat.label}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
